select a.student_id, a.student_name, b.subject_name, count(c.student_id) attended_exams from students a cross join subjects b left join examinations c on b.subject_name = c.subject_name and a.student_id = c.student_id group by a.student_id, b.subject_name, a.student_name order by a.student_id, b.subject_name;